import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  Users, AlertTriangle, Calendar, ShoppingCart, 
  CheckCircle2, ArrowUpRight, Clock
} from 'lucide-react';
import '../styles/Dashboard.css'; // Importando o CSS novo

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    totalEmAbertoFuturo: 0,
    qtdComprasMes: 0,
    maiorParcelaMes: 0,
    detalhesPorPessoa: {}
  });
  const [perfil, setPerfil] = useState(null);
  const [loading, setLoading] = useState(true);

  const hoje = new Date();
  const mesAtual = hoje.getMonth();
  const anoAtual = hoje.getFullYear();
  const mesAtualChave = `${anoAtual}-${String(mesAtual + 1).padStart(2, '0')}`;

  const colors = {
    primary: '#4361ee', secondary: '#7209b7', accent1: '#f72585',
    accent2: '#4cc9f0', success: '#00cc66', warning: '#ff9800', bg: '#f8fafc'
  };

  useEffect(() => { carregarDados(); }, []);

  async function carregarDados() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: perfilData } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      const { data: cartoes } = await supabase.from('cartoes').select('*');
      const { data: todosPerfis } = await supabase.from('profiles').select('id, nome');
      setPerfil(perfilData);

      const isProprietario = perfilData?.tipo_usuario === 'proprietario' || user.email === 'gleidson.fig@gmail.com';
      const mapaNomes = {};
      todosPerfis?.forEach(p => mapaNomes[p.id] = p.nome.split(' ')[0]);

      let query = supabase.from('compras').select('*');
      if (!isProprietario) query = query.eq('user_id', user.id);
      const { data: compras } = await query;

      let resumo = {
        totalMes: 0, totalEmAbertoFuturo: 0, qtdComprasMes: 0,
        maiorParcelaMes: 0, detalhesPorPessoa: {}
      };

      compras?.forEach(item => {
        const valorTotal = parseFloat(item.valor_total) || 0;
        const numP = parseInt(item.num_parcelas) || 1;
        const valorP = valorTotal / numP;
        const [anoC, mesC, diaC] = item.data_compra.split('-').map(Number);
        const responsavel = mapaNomes[item.user_id] || 'Outro';

        // Encontrar info do cartão para vencimento
        const infoCartao = cartoes?.find(c => c.nome === item.cartao);
        const vencimento = infoCartao?.dia_vencimento || 0;

        if (!resumo.detalhesPorPessoa[responsavel]) {
          resumo.detalhesPorPessoa[responsavel] = {
            valorNoMes: 0, qtdComprasMes: 0, totalRestanteFuturo: 0,
            ultimaParcelaDate: new Date(0),
            vencimentoAte15: 0, // Soma compras que vencem até dia 15
            vencimentoAte20: 0  // Soma compras que vencem após dia 15
          };
        }

        const p = resumo.detalhesPorPessoa[responsavel];

        let delayMes = 0;
        if (item.forma_pagamento === 'Crédito' && item.cartao !== 'À Vista') {
          if (infoCartao && diaC > infoCartao.dia_fechamento) delayMes = 1;
        }

        for (let i = 0; i < numP; i++) {
          const dtP = new Date(anoC, (mesC - 1) + delayMes + i, 1);
          const chaveP = `${dtP.getFullYear()}-${String(dtP.getMonth() + 1).padStart(2, '0')}`;

          if (dtP > p.ultimaParcelaDate) p.ultimaParcelaDate = dtP;

          if (chaveP === mesAtualChave) {
            resumo.totalMes += valorP;
            resumo.qtdComprasMes++;
            p.valorNoMes += valorP;
            p.qtdComprasMes++;
            if (valorP > resumo.maiorParcelaMes) resumo.maiorParcelaMes = valorP;

            // Lógica dos Badges: Separa o valor por dia de vencimento
            if (vencimento > 0 && vencimento <= 15) {
              p.vencimentoAte15 += valorP;
            } else if (vencimento > 15) {
              p.vencimentoAte20 += valorP;
            }
          }

          if (dtP > new Date(anoAtual, mesAtual, 1)) {
            if (chaveP !== mesAtualChave) {
              resumo.totalEmAbertoFuturo += valorP;
              p.totalRestanteFuturo += valorP;
            }
          }
        }
      });

      setStats(resumo);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  if (loading) return <div className="loading">Carregando Dashboard...</div>;

  return (
    <div className="fade-in dashboard-container" style={{ padding: '30px', backgroundColor: colors.bg, paddingBottom: '100px' }}>
      
      <div style={{ marginBottom: '35px' }}>
        <h2 style={{ margin: 0, fontWeight: 800, color: '#1e293b' }}>
          {perfil?.tipo_usuario === 'proprietario' ? 'Dashboard Global' : 'Meu Resumo'}
        </h2>
      </div>

      <div className="dashboard-grid">
        <Card title="Fatura Mês" icon={<Calendar />} value={formatMoney(stats.totalMes)} gradient={`linear-gradient(135deg, ${colors.primary}, #3f37c9)`} />
        <Card title="Dívida Futura" icon={<Clock />} value={formatMoney(stats.totalEmAbertoFuturo)} gradient={`linear-gradient(135deg, ${colors.secondary}, #560bad)`} />
        <Card title="Itens no Mês" icon={<ShoppingCart />} value={stats.qtdComprasMes} gradient={`linear-gradient(135deg, ${colors.accent2}, ${colors.primary})`} />
      </div>

      <div style={{ margin: '40px 0 20px 0' }}>
        <h3 style={{ display: 'flex', alignItems: 'center', gap: '10px', color: '#1e293b' }}>
          <Users size={22} /> Detalhamento por Pessoa
        </h3>
      </div>

      <div className="dashboard-grid">
        {Object.entries(stats.detalhesPorPessoa).map(([nome, dados]) => (
          <div key={nome} className="person-card">
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
              <span className="person-name-tag">{nome}</span>
              <ArrowUpRight size={18} color="#cbd5e1" />
            </div>

            <div style={{ marginBottom: '15px' }}>
              <span style={{ fontSize: '0.65rem', color: '#94a3b8', fontWeight: 700, textTransform: 'uppercase' }}>Total este mês</span>
              <div style={{ fontSize: '1.6rem', fontWeight: 800, color: '#1e293b' }}>{formatMoney(dados.valorNoMes)}</div>
            </div>

            {/* SEÇÃO DE BADGES POR VENCIMENTO */}
            <div className="badge-container">
              {dados.vencimentoAte15 > 0 && (
                <div className="badge-pay badge-early">
                  <Clock size={12} /> Até dia 15: {formatMoney(dados.vencimentoAte15)}
                </div>
              )}
              {dados.vencimentoAte20 > 0 && (
                <div className="badge-pay badge-late">
                  <Clock size={12} /> Dia 20+: {formatMoney(dados.vencimentoAte20)}
                </div>
              )}
            </div>

            <div style={{ marginTop: '20px', padding: '12px', background: '#f8fafc', borderRadius: '12px' }}>
              <span style={{ fontSize: '0.6rem', color: '#94a3b8', fontWeight: 700 }}>RESTANTE FUTURO</span>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: colors.secondary }}>{formatMoney(dados.totalRestanteFuturo)}</div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '15px' }}>
              <div className="mini-stat">
                <span style={{ fontSize: '0.6rem', color: '#94a3b8' }}>ITENS</span>
                <div style={{ fontWeight: 700 }}>{dados.qtdComprasMes}</div>
              </div>
              <div className="mini-stat">
                <span style={{ fontSize: '0.6rem', color: '#94a3b8' }}>QUITAÇÃO</span>
                <div style={{ fontWeight: 700 }}>{dados.ultimaParcelaDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' })}</div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const Card = ({ title, icon, value, gradient }) => (
  <div style={{ padding: '24px', borderRadius: '24px', background: gradient, color: 'white', position: 'relative', overflow: 'hidden', minHeight: '120px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
    <div style={{ position: 'absolute', right: '-10px', top: '-10px', opacity: 0.2 }}>{React.cloneElement(icon, { size: 80 })}</div>
    <div style={{ fontSize: '0.7rem', fontWeight: 600, textTransform: 'uppercase', marginBottom: '5px' }}>{title}</div>
    <div style={{ fontSize: '1.6rem', fontWeight: 800 }}>{value}</div>
  </div>
);

export default Dashboard;
